arguments.file_text:
@code {
    private int _step = 1;
    private readonly Order _order = new();

    [Parameter]
    public EventCallback<Order> OnOrderPlaced { get; set; }

    private void GoToPayment()
    {
        _step = 2;
    }

    private void GoBackToShipping()
    {
        _step = 1;
    }

    private async Task PlaceOrder()
    {
        await OnOrderPlaced.InvokeAsync(_order);
    }
}

@if (_step == 1)
{
    <ShippingStep Shipping="_order.Shipping" OnNext="GoToPayment" />
}
else
{
    <PaymentStep Payment="_order.Payment"
                 OnBack="GoBackToShipping"
                 OnPlaceOrder="PlaceOrder" />
}

@implements IDisposable
@inject IAddressValidator AddressValidator

<h3>Shipping Information</h3>

<label>
    Name
    <input @bind="Shipping.Name" disabled="@_validating" />
</label>

<label>
    Address
    <input @bind="Shipping.Address" disabled="@_validating" />
</label>

<label>
    City
    <input @bind="Shipping.City" disabled="@_validating" />
</label>

<label>
    Zip Code
    <input @bind="Shipping.ZipCode" disabled="@_validating" />
</label>

@if (!string.IsNullOrEmpty(_error))
{
    <p class="error">@_error</p>
}

<button @onclick="ValidateAndProceed" disabled="@_validating">
    @if (_validating)
    {
        <span class="spinner" aria-hidden="true"></span>
        <span>Validating…</span>
    }
    else
    {
        <span>Next</span>
    }
</button>

@code {
    private bool _validating;
    private string? _error;
    private CancellationTokenSource? _cts;

    [Parameter]
    public ShippingInfo Shipping { get; set; } = new();

    [Parameter]
    public EventCallback OnNext { get; set; }

    private async Task ValidateAndProceed()
    {
        // Cancel any in-flight validation (e.g. user went back and changed fields).
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = new CancellationTokenSource();
        var token = _cts.Token;

        _error = null;
        _validating = true;

        try
        {
            var valid = await AddressValidator.ValidateAddressAsync(
                Shipping.Address, Shipping.City, Shipping.ZipCode, token);

            token.ThrowIfCancellationRequested();

            if (valid)
            {
                await OnNext.InvokeAsync();
            }
            else
            {
                _error = "The address could not be verified. Please check your details.";
            }
        }
        catch (OperationCanceledException)
        {
            // Validation was superseded or the component is disposing — nothing to do.
        }
        finally
        {
            _validating = false;
        }
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

